import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface BankStateBase {
  balance: number;        // 即時餘額
  t1: number;             // T+1 交割款 (正負皆可)
  t2: number;             // T+2 交割款 (正負皆可)
  subscription: number;   // 已扣申購款 (通常為負項，或輸入正數程式扣除)
  loanLimit: number;      // 借貸可申請額度
  loanAvailable: number;  // 借貸可動用金額
}

export interface SinoPacState extends BankStateBase {
  usdRate: number;        // 美元匯率
  usdT1: number;          // 美金 T+1 (原幣)
  usdT2: number;          // 美金 T+2 (原幣)
}

export interface CapitalState extends BankStateBase {}

export type CurrencyType = 'TWD' | 'USD';

import React from 'react';

interface MoneyInputProps {
  label: string;
  value: number;
  onChange: (val: number) => void;
  placeholder?: string;
  note?: string;
  isNegative?: boolean; // Visual hint for deduction fields
  currency?: 'TWD' | 'USD';
  readOnly?: boolean;
}

const MoneyInput: React.FC<MoneyInputProps> = ({
  label,
  value,
  onChange,
  placeholder = "0",
  note,
  isNegative = false,
  currency = 'TWD',
  readOnly = false
}) => {

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    if (val === '') {
      onChange(0);
      return;
    }
    // Allow typing negative signs and decimals
    const num = parseFloat(val);
    if (!isNaN(num)) {
      onChange(num);
    }
  };

  return (
    <div className="flex flex-col gap-1">
      <label className="text-sm font-medium text-gray-700 flex justify-between items-center">
        {label}
        {currency === 'USD' && <span className="text-xs font-bold text-green-600 bg-green-100 px-2 py-0.5 rounded-full">USD</span>}
      </label>
      <div className="relative rounded-md shadow-sm">
        <div className="pointer-events-none absolute inset-y-0 left-0 flex items-center pl-3">
          <span className="text-gray-500 sm:text-sm">
            {currency === 'USD' ? '$' : 'NT$'}
          </span>
        </div>
        <input
          type="number"
          step={currency === 'USD' ? "0.01" : "1"}
          className={`block w-full rounded-md border-0 py-2 pl-12 pr-4 ring-1 ring-inset focus:ring-2 focus:ring-inset sm:text-sm sm:leading-6 transition-colors
            ${readOnly ? 'bg-gray-100 text-gray-500 ring-gray-200 cursor-not-allowed' : 'bg-white text-gray-900 ring-gray-300 focus:ring-indigo-600'}
            ${isNegative && !readOnly ? 'text-red-600' : ''}
          `}
          placeholder={placeholder}
          value={value === 0 ? '' : value}
          onChange={handleChange}
          readOnly={readOnly}
        />
      </div>
      {note && <p className="text-xs text-gray-500">{note}</p>}
    </div>
  );
};

export default MoneyInput;

import React from 'react';

interface SummaryCardProps {
  title: string;
  amount: number;
  subtext?: string;
  color?: 'blue' | 'green' | 'red' | 'indigo';
}

const SummaryCard: React.FC<SummaryCardProps> = ({ title, amount, subtext, color = 'indigo' }) => {
  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('zh-TW', {
      style: 'currency',
      currency: 'TWD',
      maximumFractionDigits: 0,
    }).format(val);
  };

  const colorClasses = {
    blue: 'bg-blue-50 border-blue-200 text-blue-700',
    green: 'bg-emerald-50 border-emerald-200 text-emerald-700',
    red: 'bg-rose-50 border-rose-200 text-rose-700',
    indigo: 'bg-indigo-50 border-indigo-200 text-indigo-700',
  };

  return (
    <div className={`p-4 rounded-xl border ${colorClasses[color]} flex flex-col justify-between h-full`}>
      <h3 className="text-sm font-semibold opacity-80 uppercase tracking-wider">{title}</h3>
      <div className="mt-2">
        <p className={`text-2xl font-bold ${amount < 0 ? 'text-red-600' : ''}`}>
          {formatCurrency(amount)}
        </p>
        {subtext && <p className="text-xs opacity-70 mt-1">{subtext}</p>}
      </div>
    </div>
  );
};

export default SummaryCard;

import React, { useState, useMemo } from 'react';
import { BankStateBase, SinoPacState, CapitalState } from './types';
import MoneyInput from './components/MoneyInput';
import SummaryCard from './components/SummaryCard';

// Icons
const RefreshIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/><path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16"/><path d="M16 21h5v-5"/></svg>
);

const TrashIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
);

const initialSinoPac: SinoPacState = {
  balance: 0,
  t1: 0,
  t2: 0,
  subscription: 0,
  loanLimit: 0,
  loanAvailable: 0,
  usdRate: 32.5,
  usdT1: 0,
  usdT2: 0,
};

