  // SinoPac Calculations
  const sinoPacUsdT1InTwd = Math.round(sinoPac.usdT1 * sinoPac.usdRate);
  const sinoPacUsdT2InTwd = Math.round(sinoPac.usdT2 * sinoPac.usdRate);

  // Note: Subscription is deducted. Loans are available assets. 
  // T1/T2: Positive = Receivable, Negative = Payable (Standard interpretation, but we let user decide sign)
  // Logic: Final Projected = Balance + T1 + T2 - Subscription + Loan Available

  const sinoPacProjected = useMemo(() => {
    const twdPart = sinoPac.balance + sinoPac.t1 + sinoPac.t2 - sinoPac.subscription + sinoPac.loanAvailable;
    const usdPart = sinoPacUsdT1InTwd + sinoPacUsdT2InTwd;
    return twdPart + usdPart;
  }, [sinoPac, sinoPacUsdT1InTwd, sinoPacUsdT2InTwd]);

  // Capital Calculations
  const capitalProjected = useMemo(() => {
    return capital.balance + capital.t1 + capital.t2 - capital.subscription + capital.loanAvailable;
  }, [capital]);

  // Grand Totals
  const totalBalance = sinoPac.balance + capital.balance;
  const totalSettlement = (sinoPac.t1 + sinoPac.t2 + sinoPacUsdT1InTwd + sinoPacUsdT2InTwd) + (capital.t1 + capital.t2);
